<?php declare(strict_types=1); if (!defined('MNS_CONTROLLER_RENDER')) { require_once __DIR__ . '/../../../backend/controllers/timesheet_controller.php'; $_GET['action']='summary'; handleTimesheetRequest(); return; } require_once __DIR__ . '/../../../backend/includes/helpers.php'; require_once __DIR__ . '/../../../backend/includes/role_check.php'; requireRole(['EXPERT']); require_once __DIR__ . '/../includes/header.php'; ?>
<div class="d-flex"><?php require_once __DIR__ . '/../includes/sidebar.php'; ?><main class="container-fluid py-4"><h1 class="h4 mb-3">Synthese temps par mission</h1><div class="table-responsive bg-white border rounded"><table class="table table-hover align-middle mb-0"><thead class="table-light"><tr><th>Mission</th><th>Prevues</th><th>Saisies</th><th>Validees</th><th>Refusees</th><th>Ecart prevu/valide</th><th>Consommation</th></tr></thead><tbody><?php foreach (($summary ?? []) as $row): ?><?php $estimated=(float)($row['estimated_hours'] ?? 0); $valid=(float)$row['total_valide']; $rate=$estimated>0?round($valid*100/$estimated,2):0; ?><tr><td><?php echo e($row['title']); ?></td><td><?php echo e((string)$row['estimated_hours']); ?></td><td><?php echo e((string)$row['total_saisi']); ?></td><td><?php echo e((string)$row['total_valide']); ?></td><td><?php echo e((string)$row['total_refuse']); ?></td><td><?php echo e((string)round($estimated-$valid,2)); ?></td><td><?php echo e((string)$rate); ?>%</td></tr><?php endforeach; ?></tbody></table></div></main></div><?php require_once __DIR__ . '/../includes/footer.php'; ?>
